	Destroy(context.Context, *DestroyRequest) (*DestroyResponse, error)
	GetAddress(context.Context, *GetAddressRequest) (*GetAddressResponse, error)
	GetAddressPresentation(context.Context, *GetAddressPresentationRequest) (*GetAddressPresentationResponse, error)
	GetAudioModeIsVoip(context.Context, *GetAudioModeIsVoipRequest) (*GetAudioModeIsVoipResponse, error)
	GetCallAudioState(context.Context, *GetCallAudioStateRequest) (*GetCallAudioStateResponse, error)
	GetCallerDisplayName(context.Context, *GetCallerDisplayNameRequest) (*GetCallerDisplayNameResponse, error)
	GetCallerDisplayNamePresentation(context.Context, *GetCallerDisplayNamePresentationRequest) (*GetCallerDisplayNamePresentationResponse, error)
	GetCallerNumberVerificationStatus(context.Context, *GetCallerNumberVerificationStatusRequest) (*GetCallerNumberVerificationStatusResponse, error)
	GetConference(context.Context, *GetConferenceRequest) (*GetConferenceResponse, error)
